import React from 'react';
import './PageBorder.css';

const PETAL = 'M 0 0 C -4 -9 -5 -22 0 -34 C 5 -22 4 -9 0 0';
const ANGLES = [0, 22, -22, 50, -50, 78, -78];

export default function PageBorder() {
  return (
    <div className="page-border" aria-hidden="true">
      <div className="border-lotus">
        <svg
          viewBox="-40 -40 80 46"
          width="80"
          height="46"
          xmlns="http://www.w3.org/2000/svg"
        >
          {ANGLES.map((a) => (
            <path
              key={a}
              d={PETAL}
              fill="#8B1538"
              fillOpacity="0.75"
              transform={`rotate(${a})`}
            />
          ))}
          {/* centre dot */}
          <circle cx="0" cy="0" r="2.5" fill="#8B1538" fillOpacity="0.9" />
        </svg>
      </div>
    </div>
  );
}
